solution_code:
#include <cstring>
#include <iostream>

int main()
{
    const char* colors[]{ "red", "orange", "yellow", "green", "blue" };

    int n{};
    std::cin >> n;

    const char* longest{ "" };
    std::size_t maxLen{ 0 };

    for (int i{ 0 }; i < n; ++i)
    {
        int c{};
        std::cin >> c;

        std::size_t len{ std::strlen(colors[c]) };
        if (len > maxLen)
        {
            maxLen = len;
            longest = colors[c];
        }
    }

    std::cout << longest << '\n';
    std::cout << maxLen << '\n';

    return 0;
}
